import { initializeApp } from "firebase/app";
import { getAuth } from "firebase/auth";
import { getFirestore } from "firebase/firestore";
import { getDatabase } from "firebase/database";
import { getAnalytics } from "firebase/analytics";

const firebaseConfig = {
  apiKey: "AIzaSyCQsAywd9YMgyZRJlW_gewcOZQKWM_N-7U",
  authDomain: "spotify-app-ec883.firebaseapp.com",
  projectId: "spotify-app-ec883",
  storageBucket: "spotify-app-ec883.firebasestorage.app",
  messagingSenderId: "316774609008",
  appId: "1:316774609008:web:13ed3c24a8795ad729c4b5",
  measurementId: "G-HVEDJVTFL9"
};

// Initialize Firebase
const app = initializeApp(firebaseConfig);
const auth = getAuth(app);
const db = getFirestore(app);
const rtdb = getDatabase(app);
const analytics = getAnalytics(app);

export { app, auth, db, rtdb, analytics };

import { User, ChatMessage, UserPlaylist } from '../types';
import { auth, db, rtdb } from './firebase';
import { 
  createUserWithEmailAndPassword, 
  signInWithEmailAndPassword, 
  signOut,
  GoogleAuthProvider,
  signInWithPopup
} from 'firebase/auth';
import { 
  doc, 
  setDoc, 
  getDoc, 
  updateDoc, 
  collection, 
  query, 
  where, 
  getDocs,
  onSnapshot
} from 'firebase/firestore';
import { 
  ref, 
  set, 
  push, 
  onValue, 
  off, 
  get as getRtdb, 
  onDisconnect,
  serverTimestamp
} from 'firebase/database';

// Helper to remove undefined values
const cleanData = (obj: any) => {
  return JSON.parse(JSON.stringify(obj));
};

// Helper to sanitize email for RTDB paths
const sanitize = (email: string) => email.replace(/\./g, '_');

export const authService = {

  // 1. SIGN UP
  signup: async (name: string, email: string, password: string): Promise<User> => {
    try {
      const userCredential = await createUserWithEmailAndPassword(auth, email, password);
      const uid = userCredential.user.uid;

      const newUser: User = {
        name,
        email,
        image: '',
        friends: [],
        playlists: [],
        likedSongs: [],
        favoriteArtists: [],
        history: [],
        chats: {}
      };

      // Create User Profile in Firestore
      await setDoc(doc(db, "users", uid), cleanData({
        ...newUser,
        settings: { volume: 1 }
      }));

      // Initialize Status in RTDB
      const sanitizedEmail = sanitize(email);
      await set(ref(rtdb, `status/${sanitizedEmail}`), {
          status: 'online',
          timestamp: serverTimestamp(),
          song: null
      });

      return newUser;

    } catch (error: any) {
      if (error.code === 'auth/email-already-in-use') {
        throw new Error('User already exists.');
      }
      throw new Error(error.message || 'Signup failed');
    }
  },

  // 2. LOGIN
  login: async (email: string, password: string): Promise<User> => {
    try {
      const userCredential = await signInWithEmailAndPassword(auth, email, password);
      const uid = userCredential.user.uid;
      const sanitizedEmail = sanitize(email);

      // Set status to online in RTDB
      const statusRef = ref(rtdb, `status/${sanitizedEmail}`);
      await set(statusRef, {
          status: 'online',
          timestamp: serverTimestamp()
      });
      onDisconnect(statusRef).set({
          status: 'offline',
          timestamp: serverTimestamp()
      });

      // Get Profile from Firestore
      const userDocRef = doc(db, "users", uid);
      const userDoc = await getDoc(userDocRef);

      if (!userDoc.exists()) {
        throw new Error("User data not found");
      }

      const userData = userDoc.data();

      // Get Chats from RTDB
      const chatsRef = ref(rtdb, `chats/${sanitizedEmail}`);
      const chatsSnap = await getRtdb(chatsRef);
      const rtdbChats = chatsSnap.exists() ? chatsSnap.val() : {};

      // Transform RTDB chats object to array format expected by app
      const formattedChats: Record<string, ChatMessage[]> = {};
      Object.keys(rtdbChats).forEach(key => {
          if (rtdbChats[key]) {
              formattedChats[key] = Object.values(rtdbChats[key]);
          }
      });

      return {
        email: userData.email,
        name: userData.name,
        image: userData.image,
        friends: userData.friends || [],
        playlists: userData.playlists || [],
        likedSongs: userData.likedSongs || [],
        history: userData.history || [],
        favoriteArtists: userData.favoriteArtists || [],
        chats: formattedChats,
        currentActivity: { status: 'online', timestamp: Date.now() } // Initial state
      };

    } catch (error: any) {
      if (
        error.code === 'auth/invalid-credential' || 
        error.code === 'auth/user-not-found' || 
        error.code === 'auth/wrong-password' ||
        error.code === 'auth/invalid-email'
      ) {
        throw new Error("Password or Email Incorrect");
      }
      throw error;
    }
  },

  // 3. GOOGLE LOGIN
  loginWithGoogle: async (): Promise<User> => {
    try {
        const provider = new GoogleAuthProvider();
        const result = await signInWithPopup(auth, provider);
        const user = result.user;
        const uid = user.uid;
        const email = user.email || '';
        const sanitizedEmail = sanitize(email);

        const userDocRef = doc(db, "users", uid);
        const userDoc = await getDoc(userDocRef);

        // Set Status in RTDB
        const statusRef = ref(rtdb, `status/${sanitizedEmail}`);
        await set(statusRef, {
            status: 'online',
            timestamp: serverTimestamp()
        });
        onDisconnect(statusRef).set({
            status: 'offline',
            timestamp: serverTimestamp()
        });

        if (!userDoc.exists()) {
            // Create new user
            const newUser: User = {
                name: user.displayName || 'User',
                email: email,
                image: user.photoURL || '',
                friends: [],
                playlists: [],
                likedSongs: [],
                favoriteArtists: [],
                history: [],
                chats: {}
            };

            await setDoc(doc(db, "users", uid), cleanData({
                ...newUser,
                settings: { volume: 1 }
            }));

            return newUser;
        } else {
            const userData = userDoc.data();

            // Get Chats from RTDB
            const chatsRef = ref(rtdb, `chats/${sanitizedEmail}`);
            const chatsSnap = await getRtdb(chatsRef);
            const rtdbChats = chatsSnap.exists() ? chatsSnap.val() : {};

            const formattedChats: Record<string, ChatMessage[]> = {};
            Object.keys(rtdbChats).forEach(key => {
                if (rtdbChats[key]) {
                    formattedChats[key] = Object.values(rtdbChats[key]);
                }
            });

            return {
                email: userData.email,
                name: userData.name,
                image: userData.image || user.photoURL || '',
                friends: userData.friends || [],
                playlists: userData.playlists || [],
                likedSongs: userData.likedSongs || [],
                history: userData.history || [],
                favoriteArtists: userData.favoriteArtists || [],
                chats: formattedChats,
                currentActivity: { status: 'online', timestamp: Date.now() }
            };
        }
    } catch (error: any) {
        throw new Error(error.message || 'Google Login failed');
    }
  },

  // --- PLAYLIST SHARING ---

  savePublicPlaylist: async (playlist: UserPlaylist) => {
    try {
      await setDoc(doc(db, "global_playlists", playlist.id), cleanData(playlist));
    } catch (e) {
      console.error("Failed to save public playlist", e);
    }
  },

  getPublicPlaylist: async (playlistId: string): Promise<UserPlaylist | null> => {
    try {
      const docRef = doc(db, "global_playlists", playlistId);
      const docSnap = await getDoc(docRef);
      if (docSnap.exists()) {
        return docSnap.data() as UserPlaylist;
      }
      return null;
    } catch (e) {
      console.error("Failed to fetch public playlist", e);
      return null;
    }
  },

  // --- REALTIME LISTENERS ---

  // Listen to User Data (Merged Firestore Profile + RTDB Chats)
  subscribeToUserData: (callback: (data: any) => void) => {
    if (!auth.currentUser || !auth.currentUser.email) return () => {};

    const uid = auth.currentUser.uid;
    const email = auth.currentUser.email;
    const sanitizedEmail = sanitize(email);

    let firestoreData: any = null;
    let rtdbChatsData: any = null;

    const mergeAndCallback = () => {
        if (firestoreData) {
            const merged = { ...firestoreData };

            if (rtdbChatsData) {
                const formattedChats: Record<string, ChatMessage[]> = {};
                Object.keys(rtdbChatsData).forEach(key => {
                    if (rtdbChatsData[key]) {
                        formattedChats[key] = Object.values(rtdbChatsData[key]);
                    }
                });
                merged.chats = formattedChats;
            } else {
                merged.chats = {};
            }
            callback(merged);
        }
    };

    // 1. Listen to Firestore Profile
    const userRef = doc(db, "users", uid);
    const unsubFirestore = onSnapshot(userRef, (doc) => {
      if (doc.exists()) {
        firestoreData = doc.data();
        mergeAndCallback();
      }
    });

    // 2. Listen to RTDB Chats
    const chatsRef = ref(rtdb, `chats/${sanitizedEmail}`);
    const onChatsValue = onValue(chatsRef, (snapshot) => {
        rtdbChatsData = snapshot.val();
        mergeAndCallback();
    });

    return () => {
        unsubFirestore();
        off(chatsRef, 'value', onChatsValue);
    };
  },

  // Listen to CONTACTS (RTDB Status)
  subscribeToFriendsActivity: (friendEmails: string[], callback: (friendsData: any[]) => void) => {
    if (!friendEmails || friendEmails.length === 0) {
      callback([]);
      return () => {};
    }

    const listeners: Function[] = [];
    const friendsStatusMap = new Map<string, any>();

    friendEmails.forEach(email => {
        const sEmail = sanitize(email);
        const statusRef = ref(rtdb, `status/${sEmail}`);

        const onStatusValue = onValue(statusRef, (snapshot) => {
            if (snapshot.exists()) {
                const val = snapshot.val();
                friendsStatusMap.set(email, {
                    email: email,
                    currentActivity: {
                        status: val.status,
                        timestamp: val.timestamp,
                        song: val.song
                    },
                    // We don't get name/image from RTDB status, relying on store to have that from profile or previous data
                });
            } else {
                // If no status, assume offline
                friendsStatusMap.set(email, {
                    email: email,
                    currentActivity: { status: 'offline', timestamp: 0 }
                });
            }
            callback(Array.from(friendsStatusMap.values()));
        });

        listeners.push(() => off(statusRef, 'value', onStatusValue));
    });

    return () => {
        listeners.forEach(unsub => unsub());
    };
  },

  // --- ACTIONS ---

  addContact: async (contactEmail: string) => {
    if (!auth.currentUser) throw new Error("Not authenticated");
    const myRef = doc(db, "users", auth.currentUser.uid);
    const myDoc = await getDoc(myRef);

    if (myDoc.exists()) {
      const data = myDoc.data();
      const currentFriends = data.friends || [];
      if (!currentFriends.includes(contactEmail)) {
        await updateDoc(myRef, {
          friends: [...currentFriends, contactEmail]
        });
      }
    }
  },

  sendChatMessage: async (senderEmail: string, receiverEmail: string, message: ChatMessage) => {
    if (!auth.currentUser) return;

    const sEmail = sanitize(senderEmail);
    const rEmail = sanitize(receiverEmail);
    const msgData = cleanData(message);

    // Write to RTDB for both users
    const senderChatRef = ref(rtdb, `chats/${sEmail}/${rEmail}`);
    const receiverChatRef = ref(rtdb, `chats/${rEmail}/${sEmail}`);

    await push(senderChatRef, msgData);
    await push(receiverChatRef, msgData);

    // Update friend lists in Firestore if not already friends
    // 1. My Friend List
    const myRef = doc(db, "users", auth.currentUser.uid);
    const myDoc = await getDoc(myRef);
    if (myDoc.exists()) {
        const myFriends = myDoc.data().friends || [];
        if (!myFriends.includes(receiverEmail)) {
            await updateDoc(myRef, { friends: [...myFriends, receiverEmail] });
        }
    }

    // 2. Their Friend List
    const usersRef = collection(db, "users");
    const q = query(usersRef, where("email", "==", receiverEmail));
    const querySnapshot = await getDocs(q);
    if (!querySnapshot.empty) {
        const friendDoc = querySnapshot.docs[0];
        const friendFriends = friendDoc.data().friends || [];
        if (!friendFriends.includes(senderEmail)) {
            await updateDoc(friendDoc.ref, { friends: [...friendFriends, senderEmail] });
        }
    }
  },

  updateUserStatus: async (status: 'online' | 'offline' | 'listening', song?: any) => {
     if (!auth.currentUser || !auth.currentUser.email) return;

     const sEmail = sanitize(auth.currentUser.email);
     const statusRef = ref(rtdb, `status/${sEmail}`);

     const activity = cleanData({
         status,
         timestamp: serverTimestamp(),
         song: song || null
     });

     await set(statusRef, activity);

     if (status !== 'offline') {
         onDisconnect(statusRef).set({
             status: 'offline',
             timestamp: serverTimestamp(),
             song: null
         });
     }
  },

  syncPublicProfile: async (user: User) => {
    if (!auth.currentUser) return;
    const userRef = doc(db, "users", auth.currentUser.uid);
    const updates: any = {
      name: user.name,
      image: user.image,
      friends: user.friends,
      playlists: user.playlists 
    };
    await updateDoc(userRef, cleanData(updates));
  },

  syncPrivateData: async (user: User, additionalData: any) => {
     if (!auth.currentUser) return;
     const userRef = doc(db, "users", auth.currentUser.uid);
     await updateDoc(userRef, cleanData({
         playlists: user.playlists, 
         likedSongs: additionalData.likedSongs,
         history: additionalData.history,
         favoriteArtists: additionalData.favoriteArtists
     }));
  },

  searchUsers: async (queryText: string) => {
      const usersRef = collection(db, "users");
      const q = query(usersRef); 
      const querySnapshot = await getDocs(q);
      const results: any[] = [];
      const lowerQ = queryText.toLowerCase();

      querySnapshot.forEach((doc) => {
          const data = doc.data();
          if (
              (data.name && data.name.toLowerCase().includes(lowerQ)) || 
              (data.email && data.email.toLowerCase().includes(lowerQ))
          ) {
              results.push({
                  name: data.name,
                  email: data.email,
                  image: data.image
              });
          }
      });
      return results.slice(0, 10);
  },

  logout: async () => {
      if (auth.currentUser && auth.currentUser.email) {
           const sEmail = sanitize(auth.currentUser.email);
           const statusRef = ref(rtdb, `status/${sEmail}`);
           await set(statusRef, { 
               status: 'offline', 
               timestamp: serverTimestamp() 
           });
      }
      await signOut(auth);
  }
};

import { create } from 'zustand';
import { persist } from 'zustand/middleware';
import { Song, UserPlaylist, User, Friend, ChatMessage, PartySession, Artist, SearchResult } from '../types';
import { authService } from '../services/auth';
import { downloadSongWithProgress, OfflineStorage } from '../services/api';

interface PlayerState {
  isPlaying: boolean;
  isBuffering: boolean;
  isFullScreen: boolean;
  currentSong: Song | null;
  queue: Song[];
  history: Song[];
  likedSongs: Song[];
  favoriteArtists: Artist[];
  userPlaylists: UserPlaylist[];
  volume: number;
  isShuffling: boolean;
  streamingQuality: 'low' | 'normal' | 'high';
  musicSource: 'local' | 'youtube' | 'both';

  // Search History
  recentSearches: (SearchResult | string)[];

  // Audio Engine State
  audioElement: HTMLAudioElement | null;
  duration: number;

  // Offline & Downloads
  isOfflineMode: boolean;
  downloadedSongIds: string[];
  activeDownload: Song | null;
  downloadProgress: number;

  // Auth
  currentUser: User | null;

  // Social
  friends: Friend[]; // Unified list
  searchResults: { name: string, email: string, image?: string }[];
  activeChatFriendId: string | null;
  partySession: PartySession | null;

  // Realtime Cleanup
  unsubscribers: Function[];

  // Actions
  setAudioElement: (el: HTMLAudioElement) => void;
  setDuration: (duration: number) => void;
  playSong: (song: Song, newQueue?: Song[]) => void;
  togglePlay: () => void;
  setIsPlaying: (isPlaying: boolean) => void;
  setIsBuffering: (isBuffering: boolean) => void;
  setFullScreen: (isFull: boolean) => void;
  nextSong: () => void;
  prevSong: () => void;
  addToQueue: (song: Song) => void;
  setQueue: (songs: Song[]) => void;
  setVolume: (val: number) => void;
  addToHistory: (song: Song) => void;
  toggleLike: (song: Song) => void;
  toggleArtistLike: (artist: Artist) => void;
  createPlaylist: (playlist: UserPlaylist) => void;
  importPlaylist: (playlist: UserPlaylist) => void;
  addSongToPlaylist: (playlistId: string, song: Song) => void;
  removePlaylist: (id: string) => void;
  setStreamingQuality: (quality: 'low' | 'normal' | 'high') => void;
  setMusicSource: (source: 'local' | 'youtube' | 'both') => void;
  startDownload: (song: Song, url: string, filename: string) => Promise<void>;

  // Search History Actions
  addRecentSearch: (item: SearchResult | string) => void;
  removeRecentSearch: (id: string) => void;
  clearRecentSearches: () => void;

  // Network Actions
  setOfflineMode: (isOffline: boolean) => void;

  // Auth Actions
  loginUser: (user: User & { likedSongs?: Song[], history?: Song[], favoriteArtists?: Artist[], chats?: any }) => void;
  logoutUser: () => void;
  syncUserToCloud: (type?: 'public' | 'private' | 'both') => void;
  updateUserProfile: (name: string, image?: string) => void;
  initRealtimeListeners: () => void;

  // Social Actions
  searchUsers: (query: string) => Promise<void>;
  addContact: (email: string) => Promise<void>;
  refreshFriendsActivity: () => Promise<void>;
  openChat: (friendId: string | null) => void;
  sendMessage: (friendId: string, text: string) => void;
  startParty: () => void;
  stopParty: () => void;
}

export const usePlayerStore = create<PlayerState>()(
  persist(
    (set, get) => ({
      isPlaying: false,
      isBuffering: false,
      isFullScreen: false,
      currentSong: null,
      queue: [],
      history: [],
      likedSongs: [],
      favoriteArtists: [],
      userPlaylists: [],
      volume: 1,
      isShuffling: false,
      currentUser: null,
      streamingQuality: 'high',
      musicSource: 'both',
      recentSearches: [],

      // Audio Engine Initial
      audioElement: null,
      duration: 0,

      // Offline State
      isOfflineMode: !navigator.onLine,
      downloadedSongIds: [],
      activeDownload: null,
      downloadProgress: 0,

      // Social Initial State
      friends: [],
      searchResults: [],
      activeChatFriendId: null,
      partySession: null,
      unsubscribers: [],

      setAudioElement: (el) => set({ audioElement: el }),
      setDuration: (duration) => set({ duration }),

      setOfflineMode: (isOffline) => set({ isOfflineMode: isOffline }),

      playSong: (song, newQueue) => {
        const { addToHistory, currentUser } = get();
        addToHistory(song);

        if (currentUser && navigator.onLine) {
            authService.updateUserStatus('listening', song);
        }

        set((state) => ({
          currentSong: song,
          isPlaying: true,
          isBuffering: true, 
          queue: newQueue ? newQueue : state.queue,
          isFullScreen: false, 
        }));
      },

      togglePlay: () => set((state) => ({ isPlaying: !state.isPlaying })),

      setIsPlaying: (isPlaying) => {
          set({ isPlaying });
          const { currentUser, currentSong, isOfflineMode } = get();
          if (currentUser && !isPlaying && !isOfflineMode) {
             authService.updateUserStatus('online', currentSong);
          }
      },

      setIsBuffering: (isBuffering) => set({ isBuffering }),
      setFullScreen: (isFullScreen) => set({ isFullScreen }),

      nextSong: () => {
        const { queue, currentSong, isShuffling } = get();
        if (!currentSong) return;
        const currentIndex = queue.findIndex(s => s.id === currentSong.id);
        let nextIndex = isShuffling ? Math.floor(Math.random() * queue.length) : currentIndex + 1;
        if (nextIndex < queue.length) get().playSong(queue[nextIndex]);
        else set({ isPlaying: false });
      },

      prevSong: () => {
        const { queue, currentSong } = get();
        if (!currentSong) return;
        const currentIndex = queue.findIndex(s => s.id === currentSong.id);
        if (currentIndex - 1 >= 0) get().playSong(queue[currentIndex - 1]);
      },

      addToQueue: (song) => set((state) => ({ queue: [...state.queue, song] })),
      setQueue: (songs) => set({ queue: songs }),
      setVolume: (volume) => set({ volume }),
      setStreamingQuality: (quality) => set({ streamingQuality: quality }),
      setMusicSource: (source) => set({ musicSource: source }),

      addRecentSearch: (item) => set((state) => {
          const newRecent = [item, ...state.recentSearches.filter(i => {
              if (typeof i === 'string' && typeof item === 'string') return i.toLowerCase() !== item.toLowerCase();
              if (typeof i !== 'string' && typeof item !== 'string') return i.id !== item.id;
              // Filter out if types don't match (e.g. replacing a string with an object of same name? unlikely but safe)
              return true;
          })].slice(0, 10);
          return { recentSearches: newRecent };
      }),

      removeRecentSearch: (id) => set((state) => ({
          recentSearches: state.recentSearches.filter(i => {
              if (typeof i === 'string') return i !== id;
              return i.id !== id;
          })
      })),

      clearRecentSearches: () => set({ recentSearches: [] }),

      addToHistory: (song) => {
          set((state) => {
            const newHistory = [song, ...state.history.filter(s => s.id !== song.id)].slice(0, 20);
            if(navigator.onLine) setTimeout(() => get().syncUserToCloud('private'), 1000);
            return { history: newHistory };
          });
      },

      toggleLike: (song) => {
          set((state) => {
            const isLiked = state.likedSongs.some(s => s.id === song.id);
            const newLiked = isLiked ? state.likedSongs.filter(s => s.id !== song.id) : [song, ...state.likedSongs];
            if(navigator.onLine) setTimeout(() => get().syncUserToCloud('private'), 1000);
            return { likedSongs: newLiked };
          });
      },

      toggleArtistLike: (artist) => {
          set((state) => {
              const isLiked = state.favoriteArtists.some(a => a.id === artist.id);
              const newLiked = isLiked 
                  ? state.favoriteArtists.filter(a => a.id !== artist.id) 
                  : [...state.favoriteArtists, artist];
              return { favoriteArtists: newLiked };
          });
      },

      createPlaylist: (playlist) => {
        set((state) => {
           const newPlaylists = [playlist, ...state.userPlaylists];
           if(navigator.onLine) authService.savePublicPlaylist(playlist);
           if (state.currentUser) {
             const updatedUser = { ...state.currentUser, playlists: newPlaylists };
             if(navigator.onLine) setTimeout(() => get().syncUserToCloud('private'), 1000);
             return { userPlaylists: newPlaylists, currentUser: updatedUser };
           }
           return { userPlaylists: newPlaylists };
        });
      },

      importPlaylist: (playlist) => {
        set((state) => {
           if (state.userPlaylists.some(p => p.id === playlist.id)) return {};
           const newPlaylists = [playlist, ...state.userPlaylists];
           if (state.currentUser) {
             const updatedUser = { ...state.currentUser, playlists: newPlaylists };
             if(navigator.onLine) setTimeout(() => get().syncUserToCloud('private'), 1000);
             return { userPlaylists: newPlaylists, currentUser: updatedUser };
           }
           return { userPlaylists: newPlaylists };
        });
      },

      addSongToPlaylist: (playlistId, song) => {
        set((state) => {
          const newPlaylists = state.userPlaylists.map(p => {
            if (p.id === playlistId) {
               const updated = { ...p, songs: [...p.songs, song] };
               if (p.songs.some(s => s.id === song.id)) return p;
               if(navigator.onLine) authService.savePublicPlaylist(updated);
               return updated;
            }
            return p;
          });
          if (state.currentUser) {
             const updatedUser = { ...state.currentUser, playlists: newPlaylists };
             if(navigator.onLine) setTimeout(() => get().syncUserToCloud('private'), 1000);
             return { userPlaylists: newPlaylists, currentUser: updatedUser };
           }
           return { userPlaylists: newPlaylists };
        });
      },

      removePlaylist: (id) => {
        set((state) => {
           const newPlaylists = state.userPlaylists.filter(p => p.id !== id);
           if (state.currentUser) {
             const updatedUser = { ...state.currentUser, playlists: newPlaylists };
             if(navigator.onLine) setTimeout(() => get().syncUserToCloud('private'), 1000);
             return { userPlaylists: newPlaylists, currentUser: updatedUser };
           }
           return { userPlaylists: newPlaylists };
        });
      },

      startDownload: async (song, url, filename) => {
         set({ activeDownload: song, downloadProgress: 0 });
         try {
             await downloadSongWithProgress(song.id, url, filename, (progress) => {
                 set({ downloadProgress: progress });
             });

             // Mark as downloaded in state
             set(state => {
                 const newDownloads = state.downloadedSongIds.includes(song.id) 
                    ? state.downloadedSongIds 
                    : [...state.downloadedSongIds, song.id];
                 return { downloadProgress: 100, downloadedSongIds: newDownloads };
             });

             // Wait a bit before closing progress
             setTimeout(() => {
                 set({ activeDownload: null, downloadProgress: 0 });
             }, 2000);
         } catch (e) {
             console.error("Download Error", e);
             set({ activeDownload: null, downloadProgress: 0 });
         }
      },

      loginUser: (user) => {
          set({ 
            currentUser: user, 
            userPlaylists: user.playlists || [],
            likedSongs: user.likedSongs || [],
            history: user.history || [],
            favoriteArtists: user.favoriteArtists || []
          });
          get().initRealtimeListeners();
      },

      initRealtimeListeners: () => {
         const { unsubscribers, currentUser } = get();
         unsubscribers.forEach(unsub => unsub());

         if (!currentUser || !navigator.onLine) {
             set({ unsubscribers: [] });
             return;
         }

         const newUnsubscribers: Function[] = [];

         const unsubUser = authService.subscribeToUserData((data) => {
             set((state) => {
                 const updatedUser = { ...state.currentUser, ...data } as User;
                 const existingFriends = state.friends;
                 const serverContactEmails = data.friends || [];
                 const serverChats = data.chats || {};

                 const mergedFriends: Friend[] = serverContactEmails.map((email: string) => {
                     const existing = existingFriends.find(f => f.id === email);
                     // Check for chat history using sanitized key (replace dot with underscore)
                     const sanitizedKey = email.replace(/\./g, '_');
                     const chatHistory = serverChats[sanitizedKey] || serverChats[email] || [];

                     return {
                         id: email,
                         name: existing?.name || email.split('@')[0], 
                         image: existing?.image || '',
                         status: existing?.status || 'offline', 
                         currentSong: existing?.currentSong || null, 
                         lastActive: existing?.lastActive || 0,
                         chatHistory: chatHistory
                     };
                 });

                 return {
                     currentUser: updatedUser,
                     friends: mergedFriends,
                     userPlaylists: data.playlists || state.userPlaylists
                 };
             });
         });
         newUnsubscribers.push(unsubUser);

         if (currentUser.friends && currentUser.friends.length > 0) {
             const unsubFriends = authService.subscribeToFriendsActivity(currentUser.friends, (friendsData) => {
                 set((state) => {
                     const updatedFriends = state.friends.map(f => {
                         const liveData = friendsData.find((d: any) => d.email === f.id);
                         if (liveData) {
                             return {
                                 ...f,
                                 name: liveData.name || f.name,
                                 image: liveData.image || f.image,
                                 status: liveData.currentActivity?.status || 'offline',
                                 currentSong: liveData.currentActivity?.song || null,
                                 lastActive: liveData.currentActivity?.timestamp || 0
                             };
                         }
                         return f;
                     });
                     return { friends: updatedFriends };
                 });
             });
             newUnsubscribers.push(unsubFriends);
         }

         set({ unsubscribers: newUnsubscribers });
      },

      logoutUser: async () => {
        get().unsubscribers.forEach(unsub => unsub());
        if(navigator.onLine) await authService.logout();
        set({ 
            currentUser: null, 
            userPlaylists: [],
            friends: [],
            partySession: null,
            likedSongs: [],
            history: [],
            favoriteArtists: [],
            unsubscribers: []
        });
      },

      syncUserToCloud: async (type = 'both') => {
         const { currentUser, userPlaylists, likedSongs, history, favoriteArtists, isOfflineMode } = get();
         if (!currentUser || isOfflineMode) return;
         const updatedUser = { ...currentUser, playlists: userPlaylists };
         try {
             if (type === 'public' || type === 'both') await authService.syncPublicProfile(updatedUser);
             if (type === 'private' || type === 'both') await authService.syncPrivateData(updatedUser, { likedSongs, history, favoriteArtists });
         } catch (e) {
             console.error("Sync failed", e);
         }
      },

      updateUserProfile: (name, image) => {
        set((state) => {
          if (!state.currentUser) return {};
          const updatedUser = { 
              ...state.currentUser, 
              name: name,
              image: image !== undefined ? image : state.currentUser.image 
          };
          setTimeout(() => get().syncUserToCloud('public'), 100);
          return { currentUser: updatedUser };
        });
      },

      searchUsers: async (query) => {
          try {
              if (!navigator.onLine) return;
              const results = await authService.searchUsers(query);
              const { currentUser } = get();
              const filtered = results.filter(u => u.email !== currentUser?.email);
              set({ searchResults: filtered });
          } catch (e) { console.error(e); }
      },

      addContact: async (email) => {
          const { currentUser } = get();
          if (!currentUser || !navigator.onLine) return;
          await authService.addContact(email);
          set((state) => {
              if (state.friends.some(f => f.id === email)) return {};
              const newFriend: Friend = {
                  id: email,
                  name: email.split('@')[0],
                  image: '',
                  status: 'offline',
                  lastActive: 0,
                  chatHistory: []
              };
              return { 
                  friends: [...state.friends, newFriend],
                  activeChatFriendId: email 
              };
          });
          setTimeout(() => {
              get().initRealtimeListeners();
          }, 500);
      },

      refreshFriendsActivity: async () => {
          get().initRealtimeListeners();
      },

      openChat: (friendId) => set({ activeChatFriendId: friendId }),

      sendMessage: async (friendId, text) => {
          const { currentUser } = get();
          if (!currentUser) return;

          const newMessage: ChatMessage = {
              id: `msg-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`,
              senderId: currentUser.email,
              text,
              timestamp: Date.now()
          };

          // Optimistic update
          set((state) => {
              const updatedFriends = state.friends.map(f => {
                  if (f.id === friendId) {
                      return { ...f, chatHistory: [...f.chatHistory, newMessage] };
                  }
                  return f;
              });
              return { friends: updatedFriends };
          });

          if(navigator.onLine) {
             await authService.sendChatMessage(currentUser.email, friendId, newMessage);
          }
      },

      startParty: () => set((state) => {
         if (!state.currentUser) return {};
         return {
             partySession: {
                 isActive: true,
                 hostId: 'me',
                 hostName: state.currentUser.name,
                 listeners: state.activeChatFriendId ? [state.activeChatFriendId] : []
             }
         }
      }),

      stopParty: () => set({ partySession: null })
    }),
    {
      name: 'vibestream-storage',
      partialize: (state) => ({ 
        history: state.history, 
        volume: state.volume,
        likedSongs: state.likedSongs,
        favoriteArtists: state.favoriteArtists,
        userPlaylists: state.userPlaylists,
        currentUser: state.currentUser,
        streamingQuality: state.streamingQuality,
        musicSource: state.musicSource,
        recentSearches: state.recentSearches, // Persist recent searches
        downloadedSongIds: state.downloadedSongIds,
      }), 
    }
  )
);

import { User, ChatMessage, UserPlaylist } from '../types';
import { auth, db, rtdb } from './firebase';
import { 
  createUserWithEmailAndPassword, 
  signInWithEmailAndPassword, 
  signOut,
  GoogleAuthProvider,
  signInWithPopup
} from 'firebase/auth';
import { 
  doc, 
  setDoc, 
  getDoc, 
  updateDoc, 
  collection, 
  query, 
  where, 
  getDocs,
  onSnapshot
} from 'firebase/firestore';
import { 
  ref, 
  set, 
  push, 
  onValue, 
  off, 
  get as getRtdb, 
  onDisconnect,
  serverTimestamp
} from 'firebase/database';

// Helper to remove undefined values
const cleanData = (obj: any) => {
  return JSON.parse(JSON.stringify(obj));
};

// Helper to sanitize email for RTDB paths
const sanitize = (email: string) => email.replace(/\./g, '_');

export const authService = {

  // 1. SIGN UP
  signup: async (name: string, email: string, password: string): Promise<User> => {
    try {
      const userCredential = await createUserWithEmailAndPassword(auth, email, password);
      const uid = userCredential.user.uid;

      const newUser: User = {
        name,
        email,
        image: '',
        friends: [],
        playlists: [],
        likedSongs: [],
        favoriteArtists: [],
        history: [],
        chats: {}
      };

      // Create User Profile in Firestore
      await setDoc(doc(db, "users", uid), cleanData({
        ...newUser,
        settings: { volume: 1 }
      }));

      // Initialize Status in RTDB
      const sanitizedEmail = sanitize(email);
      await set(ref(rtdb, `status/${sanitizedEmail}`), {
          status: 'online',
          timestamp: serverTimestamp(),
          song: null
      });

      return newUser;

    } catch (error: any) {
      if (error.code === 'auth/email-already-in-use') {
        throw new Error('User already exists.');
      }
      throw new Error(error.message || 'Signup failed');
    }
  },

  // 2. LOGIN
  login: async (email: string, password: string): Promise<User> => {
    try {
      const userCredential = await signInWithEmailAndPassword(auth, email, password);
      const uid = userCredential.user.uid;
      const sanitizedEmail = sanitize(email);

      // Set status to online in RTDB
      const statusRef = ref(rtdb, `status/${sanitizedEmail}`);
      await set(statusRef, {
          status: 'online',
          timestamp: serverTimestamp()
      });
      onDisconnect(statusRef).set({
          status: 'offline',
          timestamp: serverTimestamp()
      });

      // Get Profile from Firestore
      const userDocRef = doc(db, "users", uid);
      const userDoc = await getDoc(userDocRef);

      if (!userDoc.exists()) {
        throw new Error("User data not found");
      }

      const userData = userDoc.data();

      // Get Chats from RTDB
      const chatsRef = ref(rtdb, `chats/${sanitizedEmail}`);
      const chatsSnap = await getRtdb(chatsRef);
      const rtdbChats = chatsSnap.exists() ? chatsSnap.val() : {};

      // Transform RTDB chats object to array format expected by app
      const formattedChats: Record<string, ChatMessage[]> = {};
      Object.keys(rtdbChats).forEach(key => {
          if (rtdbChats[key]) {
              formattedChats[key] = Object.values(rtdbChats[key]);
          }
      });

      return {
        email: userData.email,
        name: userData.name,
        image: userData.image,
        friends: userData.friends || [],
        playlists: userData.playlists || [],
        likedSongs: userData.likedSongs || [],
        history: userData.history || [],
        favoriteArtists: userData.favoriteArtists || [],
        chats: formattedChats,
        currentActivity: { status: 'online', timestamp: Date.now(), song: null } // Initial state
      };

    } catch (error: any) {
      if (
        error.code === 'auth/invalid-credential' || 
        error.code === 'auth/user-not-found' || 
        error.code === 'auth/wrong-password' ||
        error.code === 'auth/invalid-email'
      ) {
        throw new Error("Password or Email Incorrect");
      }
      throw error;
    }
  },

  // 3. GOOGLE LOGIN
  loginWithGoogle: async (): Promise<User> => {
    try {
        const provider = new GoogleAuthProvider();
        const result = await signInWithPopup(auth, provider);
        const user = result.user;
        const uid = user.uid;
        const email = user.email || '';
        const sanitizedEmail = sanitize(email);

        const userDocRef = doc(db, "users", uid);
        const userDoc = await getDoc(userDocRef);

        // Set Status in RTDB
        const statusRef = ref(rtdb, `status/${sanitizedEmail}`);
        await set(statusRef, {
            status: 'online',
            timestamp: serverTimestamp()
        });
        onDisconnect(statusRef).set({
            status: 'offline',
            timestamp: serverTimestamp()
        });

        if (!userDoc.exists()) {
            // Create new user
            const newUser: User = {
                name: user.displayName || 'User',
                email: email,
                image: user.photoURL || '',
                friends: [],
                playlists: [],
                likedSongs: [],
                favoriteArtists: [],
                history: [],
                chats: {}
            };

            await setDoc(doc(db, "users", uid), cleanData({
                ...newUser,
                settings: { volume: 1 }
            }));

            return newUser;
        } else {
            const userData = userDoc.data();

            // Get Chats from RTDB
            const chatsRef = ref(rtdb, `chats/${sanitizedEmail}`);
            const chatsSnap = await getRtdb(chatsRef);
            const rtdbChats = chatsSnap.exists() ? chatsSnap.val() : {};

            const formattedChats: Record<string, ChatMessage[]> = {};
            Object.keys(rtdbChats).forEach(key => {
                if (rtdbChats[key]) {
                    formattedChats[key] = Object.values(rtdbChats[key]);
                }
            });

            return {
                email: userData.email,
                name: userData.name,
                image: userData.image || user.photoURL || '',
                friends: userData.friends || [],
                playlists: userData.playlists || [],
                likedSongs: userData.likedSongs || [],
                history: userData.history || [],
                favoriteArtists: userData.favoriteArtists || [],
                chats: formattedChats,
                currentActivity: { status: 'online', timestamp: Date.now(), song: null }
            };
        }
    } catch (error: any) {
        throw new Error(error.message || 'Google Login failed');
    }
  },

  // --- PLAYLIST SHARING ---

  savePublicPlaylist: async (playlist: UserPlaylist) => {
    try {
      await setDoc(doc(db, "global_playlists", playlist.id), cleanData(playlist));
    } catch (e) {
      console.error("Failed to save public playlist", e);
    }
  },

  getPublicPlaylist: async (playlistId: string): Promise<UserPlaylist | null> => {
    try {
      const docRef = doc(db, "global_playlists", playlistId);
      const docSnap = await getDoc(docRef);
      if (docSnap.exists()) {
        return docSnap.data() as UserPlaylist;
      }
      return null;
    } catch (e) {
      console.error("Failed to fetch public playlist", e);
      return null;
    }
  },

  // --- REALTIME LISTENERS ---

  // Listen to User Data (Merged Firestore Profile + RTDB Chats)
  subscribeToUserData: (callback: (data: any) => void) => {
    if (!auth.currentUser || !auth.currentUser.email) return () => {};

    const uid = auth.currentUser.uid;
    const email = auth.currentUser.email;
    const sanitizedEmail = sanitize(email);

    let firestoreData: any = null;
    let rtdbChatsData: any = null;

    const mergeAndCallback = () => {
        if (firestoreData) {
            const merged = { ...firestoreData };

            if (rtdbChatsData) {
                const formattedChats: Record<string, ChatMessage[]> = {};
                Object.keys(rtdbChatsData).forEach(key => {
                    if (rtdbChatsData[key]) {
                        formattedChats[key] = Object.values(rtdbChatsData[key]);
                    }
                });
                merged.chats = formattedChats;
            } else {
                merged.chats = {};
            }
            callback(merged);
        }
    };

    // 1. Listen to Firestore Profile
    const userRef = doc(db, "users", uid);
    const unsubFirestore = onSnapshot(userRef, (doc) => {
      if (doc.exists()) {
        firestoreData = doc.data();
        mergeAndCallback();
      }
    });

    // 2. Listen to RTDB Chats
    const chatsRef = ref(rtdb, `chats/${sanitizedEmail}`);
    const onChatsValue = onValue(chatsRef, (snapshot) => {
        rtdbChatsData = snapshot.val();
        mergeAndCallback();
    });

    return () => {
        unsubFirestore();
        off(chatsRef, 'value', onChatsValue);
    };
  },

  // Listen to CONTACTS (RTDB Status)
  subscribeToFriendsActivity: (friendEmails: string[], callback: (friendsData: any[]) => void) => {
    if (!friendEmails || friendEmails.length === 0) {
      callback([]);
      return () => {};
    }

    const listeners: Function[] = [];
    const friendsStatusMap = new Map<string, any>();

    friendEmails.forEach(email => {
        const sEmail = sanitize(email);
        const statusRef = ref(rtdb, `status/${sEmail}`);

        const onStatusValue = onValue(statusRef, (snapshot) => {
            if (snapshot.exists()) {
                const val = snapshot.val();
                friendsStatusMap.set(email, {
                    email: email,
                    currentActivity: {
                        status: val.status,
                        timestamp: val.timestamp,
                        song: val.song
                    },
                    // We don't get name/image from RTDB status, relying on store to have that from profile or previous data
                });
            } else {
                // If no status, assume offline
                friendsStatusMap.set(email, {
                    email: email,
                    currentActivity: { status: 'offline', timestamp: 0 }
                });
            }
            callback(Array.from(friendsStatusMap.values()));
        });

        listeners.push(() => off(statusRef, 'value', onStatusValue));
    });

    return () => {
        listeners.forEach(unsub => unsub());
    };
  },

  // --- ACTIONS ---

  addContact: async (contactEmail: string) => {
    if (!auth.currentUser) throw new Error("Not authenticated");
    const myRef = doc(db, "users", auth.currentUser.uid);
    const myDoc = await getDoc(myRef);

    if (myDoc.exists()) {
      const data = myDoc.data();
      const currentFriends = data.friends || [];
      if (!currentFriends.includes(contactEmail)) {
        await updateDoc(myRef, {
          friends: [...currentFriends, contactEmail]
        });
      }
    }
  },

  sendChatMessage: async (senderEmail: string, receiverEmail: string, message: ChatMessage) => {
    if (!auth.currentUser) return;

    const sEmail = sanitize(senderEmail);
    const rEmail = sanitize(receiverEmail);
    const msgData = cleanData(message);

    // Write to RTDB for both users
    const senderChatRef = ref(rtdb, `chats/${sEmail}/${rEmail}`);
    const receiverChatRef = ref(rtdb, `chats/${rEmail}/${sEmail}`);

    await push(senderChatRef, msgData);
    await push(receiverChatRef, msgData);

    // Update friend lists in Firestore if not already friends
    // 1. My Friend List
    const myRef = doc(db, "users", auth.currentUser.uid);
    const myDoc = await getDoc(myRef);
    if (myDoc.exists()) {
        const myFriends = myDoc.data().friends || [];
        if (!myFriends.includes(receiverEmail)) {
            await updateDoc(myRef, { friends: [...myFriends, receiverEmail] });
        }
    }

    // 2. Their Friend List
    const usersRef = collection(db, "users");
    const q = query(usersRef, where("email", "==", receiverEmail));
    const querySnapshot = await getDocs(q);
    if (!querySnapshot.empty) {
        const friendDoc = querySnapshot.docs[0];
        const friendFriends = friendDoc.data().friends || [];
        if (!friendFriends.includes(senderEmail)) {
            await updateDoc(friendDoc.ref, { friends: [...friendFriends, senderEmail] });
        }
    }
  },

  updateUserStatus: async (status: 'online' | 'offline' | 'listening', song?: any) => {
     if (!auth.currentUser || !auth.currentUser.email) return;

     const sEmail = sanitize(auth.currentUser.email);
     const statusRef = ref(rtdb, `status/${sEmail}`);

     const activity = cleanData({
         status,
         timestamp: serverTimestamp(),
         song: song || null
     });

     await set(statusRef, activity);

     if (status !== 'offline') {
         onDisconnect(statusRef).set({
             status: 'offline',
             timestamp: serverTimestamp(),
             song: null
         });
     }
  },

  syncPublicProfile: async (user: User) => {
    if (!auth.currentUser) return;
    const userRef = doc(db, "users", auth.currentUser.uid);
    const updates: any = {
      name: user.name,
      image: user.image,
      friends: user.friends,
      playlists: user.playlists 
    };
    await updateDoc(userRef, cleanData(updates));
  },

  syncPrivateData: async (user: User, additionalData: any) => {
     if (!auth.currentUser) return;
     const userRef = doc(db, "users", auth.currentUser.uid);
     await updateDoc(userRef, cleanData({
         playlists: user.playlists, 
         likedSongs: additionalData.likedSongs,
         history: additionalData.history,
         favoriteArtists: additionalData.favoriteArtists
     }));
  },

  searchUsers: async (queryText: string) => {
      const usersRef = collection(db, "users");
      const q = query(usersRef); 
      const querySnapshot = await getDocs(q);
      const results: any[] = [];
      const lowerQ = queryText.toLowerCase();

      querySnapshot.forEach((doc) => {
          const data = doc.data();
          if (
              (data.name && data.name.toLowerCase().includes(lowerQ)) || 
              (data.email && data.email.toLowerCase().includes(lowerQ))
          ) {
              results.push({
                  name: data.name,
                  email: data.email,
                  image: data.image
              });
          }
      });
      return results.slice(0, 10);
  },

  logout: async () => {
      if (auth.currentUser && auth.currentUser.email) {
           const sEmail = sanitize(auth.currentUser.email);
           const statusRef = ref(rtdb, `status/${sEmail}`);
           await set(statusRef, { 
               status: 'offline', 
               timestamp: serverTimestamp() 
           });
      }
      await signOut(auth);
  }
};

